ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?title ?theatrical_release_date WHERE {
  ?movies a :Movies .
  ?movies p:title ?title .
  ?movies p:theatrical_release_date ?theatrical_release_date .
} }
  full: { SELECT ?title ?streaming_release_date ?theatrical_release_date WHERE {
  ?movies a :Movies .
  ?movies p:title ?title .
  ?movies p:streaming_release_date ?streaming_release_date .
  ?movies p:theatrical_release_date ?theatrical_release_date .
} }
  component_2: { SELECT ?title ?streaming_release_date WHERE {
  ?movies a :Movies .
  ?movies p:title ?title .
  ?movies p:streaming_release_date ?streaming_release_date .
} }
}

PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?streaming_release_date ?theatrical_release_date ?name WHERE {
  ?movies a :Movies .
  ?directors a :Directors .
  ?movies p:hasDirectors ?directors .
  ?movies p:streaming_release_date ?streaming_release_date .
  ?movies p:theatrical_release_date ?theatrical_release_date .
  ?directors p:name ?name .
  ?movies p:title ?title_f .
  FILTER(STR(?title_f) = "Selma")
} }
  component: { SELECT ?theatrical_release_date ?name WHERE {
  ?movies a :Movies .
  ?directors a :Directors .
  ?movies p:hasDirectors ?directors .
  ?movies p:theatrical_release_date ?theatrical_release_date .
  ?directors p:name ?name .
  ?movies p:title ?title_f .
  FILTER(STR(?title_f) = "Selma")
} }
  component_2: { SELECT ?streaming_release_date ?name WHERE {
  ?movies a :Movies .
  ?directors a :Directors .
  ?movies p:hasDirectors ?directors .
  ?movies p:streaming_release_date ?streaming_release_date .
  ?directors p:name ?name .
  ?movies p:title ?title_f .
  FILTER(STR(?title_f) = "Selma")
} }
}
